// Inter (Regular, Latin subset) — embedded so Collections PDF export never touches
// pdfkit's built-in standard-font loader, which resolves its .afm metric files via a
// hardcoded __dirname-relative fs.readFileSync() call that breaks once Electrobun's
// Bun bundler flattens src/bun into a single file (confirmed: __dirname bakes in a
// wrong absolute dev-machine path at bundle time, not a relocatable one — verified
// against a real packaged build, not just the dev server).
//
// Source: Inter v4.1 (https://github.com/rsms/inter), licensed SIL Open Font License 1.1
// — full text in ./fonts/OFL.txt. Instanced to a static Regular weight (wght=400,
// opsz=14) and subsetted to Latin + common punctuation via fonttools, then base64
// -encoded — 96 KB of original 876 KB variable font. Regenerate with:
//   python -m fontTools.varLib.instancer Inter.ttf wght=400 opsz=14 -o out.ttf
//   python -m fontTools.subset out.ttf --output-file=Inter-Regular-Latin.ttf \
//     --unicodes="U+0000-00FF,U+0131,U+0152-0153,U+02BB-02BC,U+02C6,U+02DA,U+02DC,U+2000-206F,U+2122,U+2212" \
//     --layout-features='*' --glyph-names --symbol-cmap --legacy-cmap --notdef-glyph \
//     --notdef-outline --recommended-glyphs --name-IDs='*' --name-legacy --name-languages='*'
export const INTER_REGULAR_LATIN_TTF_BASE64 =
	"";
